import React from 'react';

const About = () => {
  return (
    <section id="about" className="section fade-element">
      <h2>How CommUnity Works</h2>
      <p>Explore the powerful features of CommUnity</p>
      <p className="section-text">
        CommUnity is a platform designed to help barangays and communities
        report issues, request assistance, and receive rewards for participation.
      </p>
    </section>
  );
};

export default About;
